import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as d,e as c}from"./app-b3edeb65.js";const a={},t=c('<h2 id="http-报文" tabindex="-1"><a class="header-anchor" href="#http-报文" aria-hidden="true">#</a> HTTP 报文</h2><p>HTTP是基于客户端/服务端（C/S）的架构模型，通过一个可靠的链接来交换信息，是一个无状态的请求/响应协议。</p><p>一个HTTP&quot;客户端&quot;是一个应用程序（Web浏览器或其他任何客户端），通过连接到服务器达到向服务器发送一个或多个HTTP的请求的目的。</p><p>一个HTTP&quot;服务器&quot;同样也是一个应用程序（通常是一个Web服务，如Apache Web服务器或IIS服务器等），通过接收客户端的请求并向客户端发送HTTP响应数据。</p><p>HTTP使用统一资源标识符（Uniform Resource Identifiers, URI）来传输数据和建立连接。</p><p>用于 HTTP 协议交互的信息被称为 <strong>HTTP 报文</strong>。</p><p>请求端(客户端)的 HTTP 报文叫做请求报文，响应端(服务器端)的叫做响应报文。</p><p>HTTP 报文大致可分为报文首部和报文主体两块。两者由最初出现的 空行(<code>CR+LF</code>)来划分。通常，并不一定要有报文主体。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/IMsa2d.png" alt="IMsa2d" tabindex="0" loading="lazy"><figcaption>IMsa2d</figcaption></figure><h2 id="请求报文及响应报文的结构" tabindex="-1"><a class="header-anchor" href="#请求报文及响应报文的结构" aria-hidden="true">#</a> 请求报文及响应报文的结构</h2><p>我们来看一下请求报文和响应报文的结构。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/CxhXLm.png" alt="CxhXLm" tabindex="0" loading="lazy"><figcaption>CxhXLm</figcaption></figure><h3 id="客户端请求消息" tabindex="-1"><a class="header-anchor" href="#客户端请求消息" aria-hidden="true">#</a> 客户端请求消息</h3><p>客户端发送一个HTTP请求到服务器的请求消息包括以下格式：请求行（request line）、<strong>可选的</strong>请求头部（header）、空行和请求数据四个部分组成，下图给出了请求报文的一般格式。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/ql8JEV.png" alt="ql8JEV" tabindex="0" loading="lazy"><figcaption>ql8JEV</figcaption></figure><figure><img src="https://img.bookandmusic.cn/blog/2022/01/7V0Ram.png" alt="7V0Ram" tabindex="0" loading="lazy"><figcaption>7V0Ram</figcaption></figure><h3 id="服务器响应消息" tabindex="-1"><a class="header-anchor" href="#服务器响应消息" aria-hidden="true">#</a> 服务器响应消息</h3><p>HTTP响应也由四个部分组成，分别是：状态行、消息报头、空行和响应正文。</p><figure><img src="https://img.bookandmusic.cn/blog/2022/01/J2zeMp.jpg" alt="J2zeMp" tabindex="0" loading="lazy"><figcaption>J2zeMp</figcaption></figure><figure><img src="https://img.bookandmusic.cn/blog/2022/01/Densz2.png" alt="Densz2" tabindex="0" loading="lazy"><figcaption>Densz2</figcaption></figure><h2 id="编码提升传输速率" tabindex="-1"><a class="header-anchor" href="#编码提升传输速率" aria-hidden="true">#</a> 编码提升传输速率</h2><p>HTTP 在传输数据时可以按照数据原貌直接传输，但也可以在传输过 程中通过编码提升传输速率。通过在传输时编码，能有效地处理大量 的访问请求。但是，编码的操作需要计算机来完成，因此会消耗更多 的 CPU 等资源。</p><h3 id="报文主体和实体主体的差异" tabindex="-1"><a class="header-anchor" href="#报文主体和实体主体的差异" aria-hidden="true">#</a> 报文主体和实体主体的差异</h3><p>报文(<strong>message</strong>)是 HTTP 通信中的基本单位，由 8 位组字节流(octet sequence， 其中 octet 为 8 个比特)组成，通过 HTTP 通信传输。</p><p>实体(<strong>entity</strong>) 作为请求或响应的有效载荷数据(补充项)被传输，其内容由实</p><p>体首部和实体主体组成。<br> HTTP 报文的主体用于传输请求或响应的实体主体。</p><p>通常，报文主体等于实体主体。只有当传输中进行编码操作时，实体<br> 主体的内容发生变化，才导致它和报文主体产生差异。</p><h3 id="压缩传输的内容编码" tabindex="-1"><a class="header-anchor" href="#压缩传输的内容编码" aria-hidden="true">#</a> 压缩传输的内容编码</h3><p><code>HTTP</code> 协议中的内容编码功能就像用压缩软件压缩东西一样，对实体内容进行编码压缩，内容编码后的实体由客户端接受并解码。这可以压缩传输内容，加快传输速度。</p><img src="https://img.bookandmusic.cn/blog/2022/01/qDswkj.png" alt="qDswkj" style="zoom:50%;"><p>常用的内容编码有以下几种。</p><ul><li><strong>gzip</strong>(<strong>GNU zip</strong>)</li><li><strong>compress</strong>(<strong>UNIX</strong> 系统的标准压缩)</li><li><strong>deflate</strong>(<strong>zlib</strong>)</li><li><strong>identity</strong>(不进行编码)</li></ul><h3 id="分割发送的分块传输编码" tabindex="-1"><a class="header-anchor" href="#分割发送的分块传输编码" aria-hidden="true">#</a> 分割发送的分块传输编码</h3><p><code>HTTP</code> 通信过程中，请求的编码实体资源尚未传输完成之前，浏览器无法显示请求页面，传输大容量数据时候，通过数据分割成多块，能让浏览器逐步显示页面。这就是分块传输编码（<code>Chunked</code> <code>Transfer</code> <code>Coding</code>）。它将实体主体分成多个部分，每一块用十六进制来标记，最后一块使用<code>0（CR+LF)</code>来标记。传输给客户端，由客户端进行解码恢复。</p><img src="https://img.bookandmusic.cn/blog/2022/01/8JKiFQ.png" alt="8JKiFQ" style="zoom:50%;"><h2 id="获取部分内容的范围请求" tabindex="-1"><a class="header-anchor" href="#获取部分内容的范围请求" aria-hidden="true">#</a> 获取部分内容的范围请求</h2><p>过去，用户下载东西中断了必须要从头下载，为了解决这问题，要实现该功能需要指定下载的实体范围，指定范围发送的请求叫做范围请求（<code>Range</code> <code>Request</code>)<br> 对一份 10000 字节大小的资源，如果使用范围请求，可以只请求 5001~10000 字节内的资源。这样就算中断了，也可以向服务端指明自己需要的资源字节范围，这些需要在首部字段中表名。<br> 形式如下：</p><p><code>Range</code> : <code>bytes</code> = 5001 - 10000<br> 5001 到 10000 的<br><code>Range</code> : <code>bytes</code> = 5001 -<br> 5001 到之后全部的<br><code>Range</code> : <code>bytes</code> = -3000, 5000 - 7000<br> 从头到 3000， 5000 到 7000 的</p><img src="https://img.bookandmusic.cn/blog/2022/01/PyLtUw.png" alt="PyLtUw" style="zoom:50%;"><p>针对范围请求，响应会返回状态码为 <code>206 Partial Content</code> 的响应报文，另外，对于多重范围的范围请求，响应会在首部字段 <code>Content-Type</code> 标明 <code>multipart</code>/<code>byteranges</code> 后返回响应报文，如果服务器无法响应请求，返回状态码 <code>200 OK </code>和完整的实体内容。</p><h2 id="发送多种数据的多部分对象集合" tabindex="-1"><a class="header-anchor" href="#发送多种数据的多部分对象集合" aria-hidden="true">#</a> 发送多种数据的多部分对象集合</h2><p><code>MIME</code>（<code>Multipurpose</code> <code>Internet</code> <code>Mail</code> <code>Extensions</code>, 多用途因特网邮件扩展），它允许邮件处理文本，图片，视频等多个不同类型的数据，这使我们可以在邮件里写入文字并添加多分附件成为了现实。例如：图片等二进制数据以 <code>ASCII</code> 码字符串编码方式表名，就是利用 <code>MIME</code> 来标记数据类型，在 <code>MIME</code> 扩展中会使用一种称为多部分对象集合（<code>Multipart</code>）的方法，来容纳多份不同类型的数据。<br> 相应的，<code>HTTP</code> 协议中也采纳了多部分对象集合，发送的一份报文主体内可含有多类型实体，通常在图片或文本文件等上传时使用。<br> 多部分对象集合包括：</p><ul><li><p><code>multipart</code>/<code>form-data</code> 在 <code>Web</code> 表单文件上传使用</p><img src="https://img.bookandmusic.cn/blog/2022/01/DmeVKM.png" alt="DmeVKM" style="zoom:50%;"></li><li><p><code>multipart</code>/<code>byteranges</code> 状态码 206（<code>Partial</code> <code>Content</code>，部分内容）响应报文包含了多个范围的内容时使用。</p></li></ul><img src="https://img.bookandmusic.cn/blog/2022/01/E6VsIv.png" alt="E6VsIv" style="zoom:50%;"><p><code>HTTP</code> 报文使用这个多部分对象集合的时候，需要在首部添加 <code>Content-type</code> 字段。<br> 使用 <code>boundary</code> 字符串来划分多部分<br> 在 <code>boundary</code> 字符串指定的各个实体的起始行之前插入<code>--</code>标记（<code>--AaB03x</code>、<code>--THis_STRING_SEPARATES</code>)<br> 在多部分对象集合对应的字符串的最后插入<code>--</code>标记（<code>--AaB03x--</code>）</p><p>多部分对象集合的每个部分类型中，都可以含有首部字段。另外，可以在部分中潜逃使用多部分对象集合。</p><h2 id="内容协商返回最合适的内容" tabindex="-1"><a class="header-anchor" href="#内容协商返回最合适的内容" aria-hidden="true">#</a> 内容协商返回最合适的内容</h2><p>同一个 Web 网站可能有存着多分相同内容的页面，如中文版和英文版，内容虽然相同，单语言不同。当浏览器默认语言为哪种，访问相同的 <code>URI</code> 的 <code>Web</code> 页面时，会对应返回哪种语言的 Web 页面，这样的机制就叫做内容协商（<code>Content</code> <code>Negotiation</code>）。<br> 这协商的请求会包含在首部字段</p><ul><li><code>Accept</code></li><li><code>Accept-Charset</code></li><li><code>Accept-Encoding</code></li><li><code>Accept-Language</code></li><li><code>Content-Language</code></li></ul><p>类型：<br> 服务器驱动协商（<code>Server-driven</code> <code>Negotiation</code>)<br> 服务器通过请求的首部字段为参考自动处理，但以浏览器直接发送的信息不一定能筛选出最优的内容。<br> 客户端驱动协商（<code>Agent-driven</code> <code>Negotiation</code>)<br> 用户从浏览器显示的可选项列表中选择， 还可以利用 JS 脚本在 Web 页面自动进行上述选择。<br> 透明协商（<code>Transparent</code> <code>Negotiation</code>)<br> 上两种方法的结合体。</p>',50),i=[t];function n(r,s){return o(),d("div",null,i)}const l=e(a,[["render",n],["__file","HTTP消息结构-6bdf4513.html.vue"]]);export{l as default};
